#include <stdio.h>

int check(int A[],int n,int P[]){
	int i,j;
	for(i=0;i<12;i++){
		int flag=1;
		for(j=0;j<n;j++){
			if((P[(j+i)%12]!=A[j]))flag=0;
		}
		if(flag){
//			printf("%d %d No Leap\n",i,j);
			return 1;
		}
	}
	for(i=0;i<12;i++){
		int flag=1;
		int trig=1;
		for(j=0;j<n;j++){
			if((j+i)%12==1&&trig==1){
				if((P[(j+i)%12]+1!=A[j]))flag=0;
			}
			else if((P[(j+i)%12]!=A[j]))flag=0;
			if((j+i)%12==11){
				trig=0;
			}
		}
		if(flag){
//			printf("%d %d 1 Leap\n",i,j);
			return 1;
		}
	}
	for(i=0;i<12;i++){
		int flag=1;
		int trig=0;
		for(j=0;j<n;j++){
			if((j+i)%12==1&&trig==1){
				if((P[(j+i)%12]+1!=A[j]))flag=0;
			}
			else if((P[(j+i)%12]!=A[j]))flag=0;
			if((j+i)%12==11){
				if(trig==0){
					trig=1;
				}
				else trig=0;
			}
		}
		if(flag){
//			printf("%d %d 2 Leap\n",i,j);
			return 1;
		}
	}
	for(i=0;i<12;i++){
		int flag=1;
		int trig=0;
		for(j=0;j<n;j++){
			if((j+i)%12==1&&trig==1){
				if((P[(j+i)%12]+1!=A[j]))flag=0;
			}
			else if((P[(j+i)%12]!=A[j]))flag=0;
			if((j+i)%12==11&&j>=12){
				if(trig==0){
					trig=1;
				}
				else trig=0;
			}
		}
		if(flag){
//			printf("%d %d 3 Leap\n",i,j);
			return 1;
		}
	}
//	printf("No satisfied\n");
	return 0;
}

int main(){
	int i,n,A[30],P[12];
	P[0]=31;
	P[1]=28;
	P[2]=31;
	P[3]=30;
	P[4]=31;
	P[5]=30;
	P[6]=31;
	P[7]=31;
	P[8]=30;
	P[9]=31;
	P[10]=30;
	P[11]=31;
	scanf("%d",&n);
	for(i=0;i<n;i++){
		scanf("%d",&A[i]);
	}
	if(check(A,n,P)==1)printf("YES\n");
	else printf("NO\n");
	return 0;
}
